import{_ as e,c as o,o as s,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Продвинутый уровень: Рабочие процессы ИИ | oh-my-opencode","description":"Освойте продвинутую оркестрацию рабочих процессов ИИ в oh-my-opencode. Узнайте о командах агентов, параллельных задачах, системе Categories/Skills, хуках жизненного цикла и глубокой настройке для создания эффективных систем разработки на базе ИИ.","frontmatter":{"title":"Продвинутый уровень: Рабочие процессы ИИ | oh-my-opencode","sidebarTitle":"Работа как команда","subtitle":"Продвинутый уровень: Рабочие процессы ИИ","description":"Освойте продвинутую оркестрацию рабочих процессов ИИ в oh-my-opencode. Узнайте о командах агентов, параллельных задачах, системе Categories/Skills, хуках жизненного цикла и глубокой настройке для создания эффективных систем разработки на базе ИИ.","order":60},"headers":[],"relativePath":"ru/code-yeongyu/oh-my-opencode/advanced/index.md","filePath":"ru/code-yeongyu/oh-my-opencode/advanced/index.md"}'),i={name:"ru/code-yeongyu/oh-my-opencode/advanced/index.md"};function r(l,a,n,p,h,d){return s(),o("div",null,[...a[0]||(a[0]=[t(`<h1 id="продвинутыи-уровень" tabindex="-1">Продвинутый уровень <a class="header-anchor" href="#продвинутыи-уровень" aria-label="Permalink to &quot;Продвинутый уровень&quot;">​</a></h1><p>Эта глава посвящена продвинутым возможностям oh-my-opencode: профессиональным командам ИИ-агентов, фоновым параллельным задачам, системе Categories и Skills, хукам жизненного цикла и многому другому. Освоение этих возможностей позволит вам оркестрировать рабочие процессы ИИ как управление реальной командой, достигая более эффективного опыта разработки.</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><div class="grid-cards"><h3 id="команды-ии-агентов-обзор-10-экспертов" tabindex="-1"><a href="./ai-agents-overview/">Команды ИИ-агентов: Обзор 10 экспертов</a> <a class="header-anchor" href="#команды-ии-агентов-обзор-10-экспертов" aria-label="Permalink to &quot;[Команды ИИ-агентов: Обзор 10 экспертов](./ai-agents-overview/)&quot;">​</a></h3><p>Всестороннее введение в функциональность, варианты использования и методы вызова 10 встроенных агентов. Научитесь выбирать подходящего агента в зависимости от типа задачи, обеспечивая эффективное командное сотрудничество, параллельное выполнение задач и глубокий анализ кода.</p><h3 id="планирование-prometheus-сбор-требовании-через-интервью" tabindex="-1"><a href="./prometheus-planning/">Планирование Prometheus: Сбор требований через интервью</a> <a class="header-anchor" href="#планирование-prometheus-сбор-требовании-через-интервью" aria-label="Permalink to &quot;[Планирование Prometheus: Сбор требований через интервью](./prometheus-planning/)&quot;">​</a></h3><p>Уточнение требований и генерация рабочих планов через режим интервью. Prometheus будет продолжать задавать вопросы, пока требования не станут ясными, и автоматически консультируется с Oracle, Metis и Momus для проверки качества плана.</p><h3 id="фоновые-параллельные-задачи-работа-как-команда" tabindex="-1"><a href="./background-tasks/">Фоновые параллельные задачи: Работа как команда</a> <a class="header-anchor" href="#фоновые-параллельные-задачи-работа-как-команда" aria-label="Permalink to &quot;[Фоновые параллельные задачи: Работа как команда](./background-tasks/)&quot;">​</a></h3><p>Подробное объяснение использования системы управления фоновыми агентами. Научитесь управлению параллелизмом, опросу задач и получению результатов, позволяя нескольким ИИ-агентам одновременно обрабатывать разные задачи, что значительно повышает эффективность работы.</p><h3 id="lsp-и-ast-grep-инструменты-рефакторинга-кода" tabindex="-1"><a href="./lsp-ast-tools/">LSP и AST-Grep: Инструменты рефакторинга кода</a> <a class="header-anchor" href="#lsp-и-ast-grep-инструменты-рефакторинга-кода" aria-label="Permalink to &quot;[LSP и AST-Grep: Инструменты рефакторинга кода](./lsp-ast-tools/)&quot;">​</a></h3><p>Введение в использование инструментов LSP и AST-Grep. Демонстрация того, как реализовать анализ и операции над кодом на уровне IDE, включая навигацию по символам, поиск ссылок и структурированный поиск кода.</p><h3 id="categories-и-skills-динамическая-композиция-агентов" tabindex="-1"><a href="./categories-skills/">Categories и Skills: Динамическая композиция агентов</a> <a class="header-anchor" href="#categories-и-skills-динамическая-композиция-агентов" aria-label="Permalink to &quot;[Categories и Skills: Динамическая композиция агентов](./categories-skills/)&quot;">​</a></h3><p>Научитесь использовать систему Categories и Skills для создания специализированных суб-агентов. Реализуйте гибкую композицию агентов, динамически назначая модели, инструменты и навыки в зависимости от требований задачи.</p><h3 id="встроенные-skills-автоматизация-браузера-и-эксперт-git" tabindex="-1"><a href="./builtin-skills/">Встроенные Skills: Автоматизация браузера и эксперт Git</a> <a class="header-anchor" href="#встроенные-skills-автоматизация-браузера-и-эксперт-git" aria-label="Permalink to &quot;[Встроенные Skills: Автоматизация браузера и эксперт Git](./builtin-skills/)&quot;">​</a></h3><p>Подробное введение в варианты использования и лучшие практики трёх встроенных Skills (playwright, frontend-ui-ux, git-master). Быстрый доступ к профессиональным возможностям, таким как автоматизация браузера, проектирование UI/UX и операции с Git.</p><h3 id="хуки-жизненного-цикла-автоматизация-контекста-и-контроля-качества" tabindex="-1"><a href="./lifecycle-hooks/">Хуки жизненного цикла: Автоматизация контекста и контроля качества</a> <a class="header-anchor" href="#хуки-жизненного-цикла-автоматизация-контекста-и-контроля-качества" aria-label="Permalink to &quot;[Хуки жизненного цикла: Автоматизация контекста и контроля качества](./lifecycle-hooks/)&quot;">​</a></h3><p>Введение в использование 32 хуков жизненного цикла. Понимание того, как автоматизировать внедрение контекста, восстановление после ошибок и контроль качества, создавая полную систему автоматизации рабочих процессов ИИ.</p><h3 id="слэш-команды-предустановленные-рабочие-процессы" tabindex="-1"><a href="./slash-commands/">Слэш-команды: Предустановленные рабочие процессы</a> <a class="header-anchor" href="#слэш-команды-предустановленные-рабочие-процессы" aria-label="Permalink to &quot;[Слэш-команды: Предустановленные рабочие процессы](./slash-commands/)&quot;">​</a></h3><p>Введение в использование 6 встроенных слэш-команд. Включая /ralph-loop (цикл быстрого исправления), /refactor (рефакторинг кода), /start-work (запуск выполнения проекта) и другие распространённые рабочие процессы.</p><h3 id="глубокая-настроика-конфигурации-управление-агентами-и-разрешениями" tabindex="-1"><a href="./advanced-configuration/">Глубокая настройка конфигурации: Управление агентами и разрешениями</a> <a class="header-anchor" href="#глубокая-настроика-конфигурации-управление-агентами-и-разрешениями" aria-label="Permalink to &quot;[Глубокая настройка конфигурации: Управление агентами и разрешениями](./advanced-configuration/)&quot;">​</a></h3><p>Обучение пользователей глубокой настройке конфигурации агентов, параметров разрешений, переопределения моделей и модификации промптов. Освоение полных возможностей конфигурации, создание рабочих процессов ИИ, соответствующих стандартам команды.</p></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Step 1                  Step 2                     Step 3                          Step 4                  │</span></span>
<span class="line"><span>│  Understand AI Agents  →   Master Planning     →   Learn Dynamic Agent     →   Deep Customization      │</span></span>
<span class="line"><span>│  (Basic Concepts)          &amp; Parallel Tasks         Composition                 &amp; Automation             │</span></span>
<span class="line"><span>│                                                      (Advanced Usage)          (Expert Level)           │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Рекомендуемая последовательность</strong>:</p><ol><li><strong>Начните с команд ИИ-агентов</strong>: Понимайте обязанности и варианты использования 10 агентов — это краеугольный камень для понимания всей системы.</li><li><strong>Затем изучите планирование и параллельные задачи</strong>: Освойте планирование Prometheus и систему фоновых задач — это ядро эффективного сотрудничества.</li><li><strong>Далее изучите динамическую композицию агентов</strong>: Изучите Categories и Skills для достижения гибкой специализации агентов.</li><li><strong>Наконец изучите глубокую настройку</strong>: Освойте хуки жизненного цикла, слэш-команды и настройку конфигурации для создания полных рабочих процессов.</li></ol><p><strong>Альтернативные маршруты</strong>:</p><ul><li>Если ваша цель — <strong>быстрый старт</strong>: Сосредоточьтесь на &quot;Командах ИИ-агентов&quot; и &quot;Слэш-командах&quot;</li><li>Если ваша цель — <strong>командное сотрудничество</strong>: Погрузитесь глубже в &quot;Планирование Prometheus&quot; и &quot;Фоновые параллельные задачи&quot;</li><li>Если ваша цель — <strong>автоматизация рабочих процессов</strong>: Изучите &quot;Хуки жизненного цикла&quot; и &quot;Глубокую настройку конфигурации&quot;</li></ul><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Перед началом</p><p>Эта глава предполагает, что вы выполнили:</p><ul><li>✅ <a href="./../start/installation/">Быстрая установка и настройка</a>: Установили oh-my-opencode и настроили хотя бы один Provider</li><li>✅ <a href="./../start/sisyphus-orchestrator/">Первый взгляд на Sisyphus: Главный оркестратор</a>: Поняли базовые механизмы вызова и делегирования агентов</li><li>✅ <a href="./../platforms/provider-setup/">Настройка провайдера: Claude, OpenAI, Gemini</a>: Настроили хотя бы одного AI Provider</li></ul></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы мы рекомендуем продолжить с:</p><ul><li><strong><a href="./../faq/troubleshooting/">Диагностика конфигурации и устранение неполадок</a></strong>: Быстро находите и устраняйте проблемы при их возникновении.</li><li><strong><a href="./../appendix/configuration-reference/">Справочник по конфигурации</a></strong>: Просмотрите полную схему файла конфигурации и поймите все параметры конфигурации.</li><li><strong><a href="./../appendix/claude-code-compatibility/">Совместимость с Claude Code</a></strong>: Узнайте, как перенести существующие рабочие процессы Claude Code в oh-my-opencode.</li></ul>`,15)])])}const g=e(i,[["render",r]]);export{u as __pageData,g as default};
